import torch
import torch.nn as nn
import torch.nn.functional as F


def _gn(num_channels):
    num_groups = min(8, num_channels)
    while num_channels % num_groups != 0:
        num_groups -= 1
    return nn.GroupNorm(num_groups, num_channels)


class segformer_lite_mlp_decoder_unet(nn.Module):
    class RefConv(nn.Module):
        def __init__(self, in_ch, out_ch, kernel_size=3, stride=1, groups=1):
            super().__init__()
            pad = kernel_size // 2
            self.pad = nn.ReflectionPad2d(pad)
            self.conv = nn.Conv2d(in_ch, out_ch, kernel_size, stride=stride, padding=0, groups=groups, bias=False)

        def forward(self, x):
            return self.conv(self.pad(x))

    class Block(nn.Module):
        def __init__(self, in_ch, out_ch):
            super().__init__()
            self.proj = nn.Conv2d(in_ch, out_ch, 1, bias=False) if in_ch != out_ch else nn.Identity()
            self.net = nn.Sequential(
                segformer_lite_mlp_decoder_unet.RefConv(in_ch, out_ch, 3),
                _gn(out_ch),
                nn.GELU(),
                segformer_lite_mlp_decoder_unet.RefConv(out_ch, out_ch, 3),
                _gn(out_ch),
            )
            self.act = nn.GELU()

        def forward(self, x):
            return self.act(self.net(x) + self.proj(x))

    class Down(nn.Module):
        def __init__(self, in_ch, out_ch):
            super().__init__()
            self.down = segformer_lite_mlp_decoder_unet.RefConv(in_ch, out_ch, 3, stride=2)
            self.block = segformer_lite_mlp_decoder_unet.Block(out_ch, out_ch)

        def forward(self, x):
            return self.block(self.down(x))

    class Up(nn.Module):
        def __init__(self, in_ch, skip_ch, out_ch):
            super().__init__()
            self.fuse = nn.Sequential(
                nn.Conv2d(in_ch + skip_ch, out_ch, 1, bias=False),
                _gn(out_ch),
                nn.GELU(),
            )
            self.block = segformer_lite_mlp_decoder_unet.Block(out_ch, out_ch)

        def forward(self, x, skip):
            x = F.interpolate(x, size=skip.shape[-2:], mode="bilinear", align_corners=False)
            x = torch.cat([x, skip], dim=1)
            return self.block(self.fuse(x))

    def __init__(self, in_channels=1, out_channels=1, n_c=16, depth=7):
        super().__init__()
        depth = max(1, int(depth))
        chans = [min(n_c * (2 ** i), n_c * 8) for i in range(depth)]

        self.stem = self.Block(in_channels, chans[0])
        self.encoder = nn.ModuleList([
            self.Down(chans[i - 1], chans[i]) for i in range(1, depth)
        ])

        self.bottleneck = nn.Sequential(
            self.Block(chans[-1], chans[-1]),
            nn.Conv2d(chans[-1], chans[-1] * 2, 1, bias=False),
            nn.GELU(),
            nn.Conv2d(chans[-1] * 2, chans[-1], 1, bias=False),
        )

        self.decoder = nn.ModuleList([
            self.Up(chans[i], chans[i - 1], chans[i - 1]) for i in range(depth - 1, 0, -1)
        ])

        self.head = nn.Sequential(
            self.RefConv(chans[0], chans[0], 3),
            _gn(chans[0]),
            nn.GELU(),
            nn.Conv2d(chans[0], out_channels, 1)
        )

    def forward(self, x):
        valid = ~torch.isnan(x)
        x_masked = torch.where(valid, x, torch.zeros_like(x))

        skips = []
        h = self.stem(x_masked)
        skips.append(h)

        for down in self.encoder:
            h = down(h)
            skips.append(h)

        h = self.bottleneck(h)

        for up, skip in zip(self.decoder, reversed(skips[:-1])):
            h = up(h, skip)

        out = self.head(h)

        if out.shape[-2:] != x.shape[-2:]:
            out = F.interpolate(out, size=x.shape[-2:], mode="bilinear", align_corners=False)

        out_valid = valid
        if out_valid.shape[1] != out.shape[1]:
            out_valid = out_valid.any(dim=1, keepdim=True).expand_as(out)

        return torch.where(out_valid, out, torch.full_like(out, float("nan")))
